from dataclasses import dataclass

@dataclass
class Triple:
    subject: str
    predicate: str
    object: str

# EVOLVE-BLOCK-START

def predict(triples: list[Triple]) -> str:
    """Generate a fluent sentence describing the given triples."""
    if not triples:
        return ""

    # Helper to turn a single triple into a natural‑language clause
    def format_clause(t: Triple) -> str:
        pred = t.predicate
        # Specific phrasing for common predicates
        if pred == "alternativeName":
            return f"{t.subject} is also known as {t.object}"
        if pred == "builder":
            return f"{t.subject} was built by {t.object}"
        if pred == "completionDate":
            return f"{t.subject} was completed on {t.object}"
        if pred == "length":
            return f"{t.subject} has a length of {t.object}"
        if pred == "powerType":
            return f"{t.subject} uses {t.object} power"
        if pred == "shipClass":
            return f"{t.subject} is a {t.object}"
        if pred == "topSpeed":
            return f"{t.subject} can reach a top speed of {t.object}"
        if pred == "owner":
            return f"{t.subject} is owned by {t.object}"
        if pred == "status":
            return f"{t.subject} is {t.object}"
        if pred == "location":
            return f"{t.subject} is located in {t.object}"
        # Default handling: make predicate readable
        pred_readable = pred.replace("_", " ")
        return f"{t.subject} {pred_readable} {t.object}"

    # Build clauses for all triples
    clauses = [format_clause(t) for t in triples]

    # Combine clauses into one fluent sentence
    if len(clauses) == 1:
        sentence = clauses[0] + "."
    else:
        sentence = "; ".join(clauses[:-1]) + "; and " + clauses[-1] + "."

    return sentence

# EVOLVE-BLOCK-END

